namespace sv_3334ee6ad0f7402eb4ccf257195abd86.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// In Blazor Server, "scoped" = one instance per SignalR circuit,
/// so each user gets independent state automatically.
/// </summary>
public class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#0d6efd";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Raised whenever Theme or AccentColor changes.
    /// Components subscribe to this to trigger re-render.
    /// </summary>
    public event Action? OnChanged;

    private void NotifyChanged() => OnChanged?.Invoke();
}

