@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Color Mode</label>
            <select class="form-select" value="@ThemeService.Theme" @onchange="OnThemeSelected">
                @foreach (var t in Enum.GetValues<Theme>())
                {
                    <option value="@t">@t</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeService.AccentColor"
                       @onchange="OnAccentColorChanged" />
                <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
            </div>
        </div>

        <div class="alert alert-info mt-3">
            <strong>Current:</strong> @ThemeService.Theme theme, accent @ThemeService.AccentColor
            <br />
            <small>Changes apply immediately to all components (including the header indicator).</small>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void OnThemeSelected(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            ThemeService.Theme = theme;
        }
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChanged -= HandleThemeChanged;
    }
}

